mapper.select:
select *
from batch.secret_version
where tenant_id = #{tenantId}

    and secret_ref = #{secretRef}


    and secret_status = #{secretStatus}


    and current_version = #{currentVersion}

order by secret_ref asc, version_no desc, id desc

select *
from batch.secret_version
where tenant_id = #{tenantId}
  and id = #{secretVersionId}

select max(version_no)
from batch.secret_version
where tenant_id = #{tenantId}
  and secret_ref = #{secretRef}

mapper.update:
update batch.secret_version
set current_version = false,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and secret_ref = #{secretRef}
  and current_version = true

update batch.secret_version
set secret_status = #{nextStatus},
    updated_by = #{updatedBy},
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{secretVersionId}
